'use client';

import { useState } from 'react';
import {
  BadgeCheck,
  BookOpen,
  Brain,
  CalendarCheck,
  Crown,
  Flame,
  Gem,
  GraduationCap,
  MessageSquareText,
  Mic,
  Mountain,
  Rocket,
  Sparkles,
  Star,
  Target,
  Trophy,
} from 'lucide-react';
import {
  AccountPanel,
  AppearancePanel,
  NotificationsPanel,
  ProfileDetailsPanel,
} from './panels';
import { ProfileViewShell } from '../../components/profile/ProfileViewShell';
import {
  activeMockUser,
  buildProfileAchievements,
  canView,
  mockProfileForm,
  mockProfileStats,
  siteContent,
} from '../../mocks';
import { useAppearanceSettings } from '../providers';

export default function ProfilePage() {
  const [tab, setTab] = useState<
    'profile' | 'notifications' | 'appearance' | 'account'
  >('profile');
  const [saved, setSaved] = useState(false);
  const [form, setForm] = useState({ ...mockProfileForm });
  const [notifications, setNotifications] = useState({
    lessonReminder: true,
    streakAlert: true,
    weeklyReport: true,
    newVocab: false,
    teacherMessages: true,
  });
  const { theme, setTheme, fontSize, setFontSize } = useAppearanceSettings();
  const profileAchievements = buildProfileAchievements(mockProfileStats);
  const achievementIconMap = {
    sparkles: <Sparkles size={20} />,
    'graduation-cap': <GraduationCap size={20} />,
    'calendar-check': <CalendarCheck size={20} />,
    flame: <Flame size={20} />,
    'book-open': <BookOpen size={20} />,
    brain: <Brain size={20} />,
    'messages-square': <MessageSquareText size={20} />,
    mic: <Mic size={20} />,
    target: <Target size={20} />,
    'badge-check': <BadgeCheck size={20} />,
    star: <Star size={20} />,
    rocket: <Rocket size={20} />,
    trophy: <Trophy size={20} />,
    crown: <Crown size={20} />,
    mountain: <Mountain size={20} />,
    gem: <Gem size={20} />,
  } as const;

  if (!canView('profile', activeMockUser.role)) return null;

  return (
    <ProfileViewShell
      title={siteContent.profile.title}
      subtitle={`${siteContent.profile.subtitle} · ${activeMockUser.role}`}
      avatar={activeMockUser.avatarInitials}
      name={form.name}
      meta={`${activeMockUser.targetLevel} · ${activeMockUser.role}`}
      badges={[
        { label: 'Upper-Intermediate' },
        { label: 'Active learner', variant: 'green' },
      ]}
      stats={[
        { value: String(mockProfileStats.wordsLearned), label: 'Words' },
        { value: String(mockProfileStats.lessonsCompleted), label: 'Lessons' },
        { value: String(mockProfileStats.streakDays), label: 'Streak' },
      ]}
      achievements={profileAchievements.map((achievement) => ({
        icon: achievementIconMap[achievement.icon],
        label: achievement.label,
        description: achievement.description,
        unlocked: achievement.unlocked,
      }))}
      tab={tab}
      onTabChange={setTab}
      tabs={[
          {
            value: 'profile',
            label: 'Profile',
            panel: (
              <ProfileDetailsPanel
                form={form}
                setForm={setForm}
                saved={saved}
                viewerRole={activeMockUser.role}
                onSave={() => {
                  setSaved(true);
                  setTimeout(() => setSaved(false), 2500);
                }}
              />
            ),
          },
          {
            value: 'notifications',
            label: 'Notifications',
            panel: (
              <NotificationsPanel
                notifications={notifications}
                setNotifications={setNotifications}
              />
            ),
          },
          {
            value: 'appearance',
            label: 'Appearance',
            panel: (
              <AppearancePanel
                theme={theme}
                setTheme={setTheme}
                fontSize={fontSize}
                setFontSize={setFontSize}
              />
            ),
          },
          {
            value: 'account',
            label: 'Account',
            panel: <AccountPanel />,
          },
      ]}
    />
  );
}
